module top_module(
  input [n-1:0] data_in,
  input [n-1:0] in2,
  output [n-1:0] out_AND,
  output [n-1:0] out_OR,
  output [n-1:0] out_XOR,
  output [n-1:0] out_NOT
);parameter n = 8; // number of input bits

assign out_AND = data_in & in2;
assign out_OR = data_in | in2;
assign out_XOR = data_in ^ in2;
assign out_NOT = ~data_in;

endmodule
